12	    [-1, -1], [0, -1], [1, -1],
13	    [-1, 0],           [1, 0],
14	    [-1, 1],  [0, 1],  [1, 1],
15	  ];
16	
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of neighborOffsets) {
19	      const nx = x + dx;
20	      const ny = y + dy;
21	      const key = `${nx},${ny}`;
22	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
23	    }
24	  }
25	
26	  const result: Cell[] = [];
27	
28	  for (const [key, count] of neighborCounts) {
29	    const isAlive = liveSet.has(key);
30	    if (isAlive && (count === 2 || count === 3)) {
31	      const [xStr, yStr] = key.split(',');
32	      result.push([Number(xStr), Number(yStr)]);
33	    } else if (!isAlive && count === 3) {
34	      const [xStr, yStr] = key.split(',');
35	      result.push([Number(xStr), Number(yStr)]);
36	    }
37	  }
38	
39	  return result;
